     // --- Zoom keybindings ---

-    _onZoom(stepFn) {
+    _onZoom(stepFn, direction) {
         const metaWindow = global.display.focus_window;
         if (!metaWindow) return;
         const state = this._scaleManager.getOrCreateState(metaWindow);
-        const newScale = stepFn(state.scaleFactor);
-        if (Math.abs(newScale - state.scaleFactor) < SCALE_EPSILON) return;
+        const currentScale = state.scaleFactor;
+        const newScale = stepFn(currentScale);
+
+        // If already at minimum scale and zooming out further, minimize
+        // (turns the window into a stamp on the shelf)
+        if (direction === 'out' &&
+            Math.abs(currentScale - MIN_SCALE) < SCALE_EPSILON) {
+            metaWindow.minimize();
+            return;
+        }
+
+        if (Math.abs(newScale - currentScale) < SCALE_EPSILON) return;
         if (WindowStateHandler.isMaximized(metaWindow) || WindowStateHandler.isTiled(metaWindow))
             WindowStateHandler.unmaximizeForScale(metaWindow);
         this._scaleManager.manualScale(metaWindow, newScale);

