-            if (this._previewSuppressed)
+            if (this._hoverSuppressed)
                 return Clutter.EVENT_PROPAGATE;
-            this._showPreview(metaWindow, container);
+            this._expandStamp(container, metaWindow);
             return Clutter.EVENT_PROPAGATE;
         });
         container.connect('leave-event', () => {
-            this.hidePreview();
+            this._collapseStamp(container);
             return Clutter.EVENT_PROPAGATE;
         });
     }

-    _showPreview(metaWindow, container) {
-        this.hidePreview();
-
-        const actor = metaWindow.get_compositor_private();
-        if (!actor)
-            return;
+    _expandStamp(container, metaWindow) {
+        // Collapse any previously expanded stamp
+        this.collapseHover();

         const frameRect = metaWindow.get_frame_rect();
+        const clone = container.get_first_child();
+        if (!clone)
+            return;

-        const clone = new Clutter.Clone({
-            source: actor,
-            width: frameRect.width,
-            height: frameRect.height,
-            reactive: false,
-        });
+        // Save original size and position for restoration
+        this._expandedContainer = container;
+        this._expandedOriginalSize = {
+            w: container.width,
+            h: container.height,
+        };
+        this._expandedOriginalPos = {
+            x: container.x,
+            y: container.y,
+        };

-        this._previewContainer = new St.Widget({
-            style_class: 'mutter-butter-hover-preview',
-            reactive: false,
-            width: frameRect.width,
-            height: frameRect.height,
-        });
-        this._previewContainer.add_child(clone);
+        // Expand clone and container to full window size
+        const fullW = frameRect.width;
+        const fullH = frameRect.height;
+        clone.set_size(fullW, fullH);
