-        const [stampX, stampY] = container.get_transformed_position();
+        // Reposition so the expanded view doesn't go off screen
         const monGeo = global.display.get_monitor_geometry(metaWindow.get_monitor());
+        let newX = container.x;
+        let newY = container.y - fullH + this._expandedOriginalSize.h;
+
+        // Clamp to monitor
+        if (newX + fullW > monGeo.x + monGeo.width)
+            newX = monGeo.x + monGeo.width - fullW;
+        if (newX < monGeo.x)
+            newX = monGeo.x;
+        if (newY < monGeo.y)
+            newY = monGeo.y;
+        if (newY + fullH > monGeo.y + monGeo.height)
+            newY = monGeo.y + monGeo.height - fullH;
